#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int L[N], G[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &L[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &G[i]);
        }
        int front = 1, back = 1;
        for (int i = 0; i < N; i++) {
            if (L[i] > G[i]) {
                front = 0;
            }
            if (L[i] > G[N - i - 1]) {
                back = 0;
            }
        }
        if (front && back) {
            printf("both\n");
        } else if (front) {
            printf("front\n");
        } else if (back) {
            printf("back\n");
        } else {
            printf("none\n");
        }
    }
    return 0;
}

