        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] L = new int[N];
            int[] G = new int[N];
            for (int i = 0; i < N; i++) {
                L[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                G[i] = sc.nextInt();
            }
            int front = 1, back = 1;
            for (int i = 0; i < N; i++) {
                if (L[i] > G[i]) {
                    front = 0;
                }
                if (L[i] > G[N - i - 1]) {
                    back = 0;
                }
            }
            if (front == 1 && back == 1) {
                System.out.println("both");
            } else if (front == 1) {
                System.out.println("front");
